recognition.onend = () => {
    isListening = false;
    console.log("음성 인식이 중단되었습니다.");

    // [수정] 사용자가 직접 끄지 않았고, TTS 재생이나 발음 연습 등 다른 작업으로 인해
    // 일시적으로 중단된 상태가 아닐 때만 자동 재시작을 시도합니다.
    // 이 로직은 모바일 브라우저가 'no-speech' 등의 이유로 인식을 자동으로 끊었을 때를 대비합니다.
    if (!userManuallyStopped && !isTtsPlaying && !isTemporarilyIgnoring) {
        setTimeout(() => {
            // 재시작 직전에도 상태를 다시 한번 확인하여 안정성을 높입니다.
            if (!userManuallyStopped && !isListening) {
                try {
                    console.log("네트워크 또는 유휴 상태로 인한 자동 재시작...");
                    recognition.start();
                } catch (e) {
                    console.error("자동 재시작 실패:", e);
                }
            }
        }, 100); // 짧은 딜레이로 '띡띡' 소리 방지
    }
    updateVoiceButtonUI();
};

